head.script:
// NTIS/실적신고/화물운송실적신고(tn_403_01_05b) -업로드


scwin.memJson = $c.data.getMemInfo();
scwin.loUpperLobranCd = scwin.memJson.loUpperLobranCd;
if (scwin.loUpperLobranCd == null) {
    scwin.loUpperLobranCd = "";
}




scwin.onpageload = function() {
    scwin.params = $c.data.getParameter();
    console.log(scwin.params);
    var lobranCd     = $c.gus.cfIsNull(scwin.params["lobranCd"]) ? "" : scwin.params["lobranCd"];
    var odrNo        = $c.gus.cfIsNull(scwin.params["odrNo"]) ? "" : scwin.params["odrNo"];
    var commSeq      = $c.gus.cfIsNull(scwin.params["commSeq"]) ? "" : scwin.params["commSeq"];
    var wrkPathSeq   = $c.gus.cfIsNull(scwin.params["wrkPathSeq"]) ? "" : scwin.params["wrkPathSeq"];
    var wrkStpSeq    = $c.gus.cfIsNull(scwin.params["wrkStpSeq"]) ? "" : scwin.params["wrkStpSeq"];
    var transSeq     = $c.gus.cfIsNull(scwin.params["transSeq"]) ? "" : scwin.params["transSeq"];
    var rsltsStdDt   = $c.gus.cfIsNull(scwin.params["rsltsStdDt"]) ? "" : scwin.params["rsltsStdDt"];

    var strCurrDate  = $c.date.getServerDateTime("yyyyMMdd")  // 서버를 기준으로 현재 날짜 반환

    var crn          = $c.gus.cfIsNull(scwin.params["crn"]) ? "" : scwin.params["crn"];
    var pchsCrn      = $c.gus.cfIsNull(scwin.params["pchsCrn"]) ? "" : scwin.params["pchsCrn"];  
    var cargoClsCd   = $c.gus.cfIsNull(scwin.params["cargoClsCd"]) ? "" : scwin.params["cargoClsCd"];
    var pchsDeptCd   = $c.gus.cfIsNull(scwin.params["pchsDeptCd"]) ? "" : scwin.params["pchsDeptCd"];
    var ordRegId     = $c.gus.cfIsNull(scwin.params["ordRegId"]) ? "" : scwin.params["ordRegId"];
    var transRegId   = $c.gus.cfIsNull(scwin.params["transRegId"]) ? "" : scwin.params["transRegId"];
    var pchsSystemYn = $c.gus.cfIsNull(scwin.params["pchsSystemYn"]) ? "" : scwin.params["pchsSystemYn"];

    var bilgClntNo   = $c.gus.cfIsNull(scwin.params["bilgClntNo"]) ? "" : scwin.params["bilgClntNo"];
    var sellAmt      = $c.gus.cfIsNull(scwin.params["sellAmt"]) ? "" : scwin.params["sellAmt"];
    var sellVat      = $c.gus.cfIsNull(scwin.params["sellVat"]) ? "" : scwin.params["sellVat"];
    var sellTot      = $c.gus.cfIsNull(scwin.params["sellTot"]) ? "" : scwin.params["sellTot"];
    var vehclNo      = $c.gus.cfIsNull(scwin.params["vehclNo"]) ? "" : scwin.params["vehclNo"];
    var vehclArvDt   = $c.gus.cfIsNull(scwin.params["vehclArvDt"]) ? "" : scwin.params["vehclArvDt"];
    var vehclPchsAmt = $c.gus.cfIsNull(scwin.params["vehclPchsAmt"]) ? "" : scwin.params["vehclPchsAmt"];
    var pchsClntNo   = $c.gus.cfIsNull(scwin.params["pchsClntNo"]) ? "" : scwin.params["pchsClntNo"];
    var pchsCtrtStDt = $c.gus.cfIsNull(scwin.params["pchsCtrtStDt"]) ? "" : scwin.params["pchsCtrtStDt"];
    var pchsPchsAmt  = $c.gus.cfIsNull(scwin.params["pchsPchsAmt"]) ? "" : scwin.params["pchsPchsAmt"];
    var pchsVehcl    = $c.gus.cfIsNull(scwin.params["pchsVehcl"]) ? "" : scwin.params["pchsVehcl"];
    var upperCommCd  = $c.gus.cfIsNull(scwin.params["upperCommCd"]) ? "" : scwin.params["upperCommCd"];
    var upperCommNm  = $c.gus.cfIsNull(scwin.params["upperCommNm"]) ? "" : scwin.params["upperCommNm"];
    var confirmYn    = $c.gus.cfIsNull(scwin.params["confirmYn"]) ? "" : scwin.params["confirmYn"];

    ds_search.set("lobranCd", lobranCd);
    ds_search.set("odrNo", odrNo);
    ds_search.set("commSeq", commSeq);
    ds_search.set("wrkPathSeq", wrkPathSeq);
    ds_search.set("wrkStpSeq", wrkStpSeq);
    ds_search.set("transSeq", transSeq);
    ds_search.set("rsltsStdDt", rsltsStdDt);

    ds_search.set("crn", crn);
    ds_search.set("pchsCrn", pchsCrn);
    ds_search.set("cargoClsCd", cargoClsCd);
    ds_search.set("pchsDeptCd", pchsDeptCd);
    ds_search.set("ordRegId", ordRegId);
    ds_search.set("transRegId", transRegId);
    ds_search.set("pchsSystemYn", pchsSystemYn);

    ds_search.set("bilgClntNo", bilgClntNo);
    ds_search.set("sellAmt", sellAmt);
    ds_search.set("sellVat", sellVat);
    ds_search.set("sellTot", sellTot);
    ds_search.set("vehclNo", vehclNo);
    ds_search.set("vehclArvDt", vehclArvDt);
    ds_search.set("vehclPchsAmt", vehclPchsAmt);
    ds_search.set("pchsClntNo", pchsClntNo);
    ds_search.set("pchsCtrtStDt", pchsCtrtStDt);
    ds_search.set("pchsPchsAmt", pchsPchsAmt);
    ds_search.set("pchsVehcl", pchsVehcl);

    ds_search.set("upperCommCd", upperCommCd);
    ds_search.set("upperCommNm", upperCommNm);
    ds_search.set("confirmYn", confirmYn);  // ?? ds_search.NameValue(1, "confirmYn") = paramArray[0][46];

    scwin.f_Retrieve();
};


//-----------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-----------------------------------------------------------------------------
scwin.f_Retrieve = function() {
    $c.sbm.execute(sbm_retrieve);
};



//-----------------------------------------------------------------------------
// 저장 
//-----------------------------------------------------------------------------
scwin.f_Save = async function() {
    //변경사항 확인
    if (ds_330.getModifiedIndex().length == 0) {
        await $c.gus.cfAlertMsg("변경사항이 없습니다."); //변경사항이 없습니다.
        return;
    }


    for (var i = 1; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "sellAmt") + ds_330.getCellData(i, "sellVat") != ds_330.getCellData(i-1, "sellAmt") + ds_330.getCellData(i-1, "sellVat")) {
            await $c.win.alert("합계금액이 일치하지 않습니다.");
            return;
        }
    } 

    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "bilgClntNo") == "") {
            await $c.win.alert("계약정보는 필수 항목입니다.");
            return;
        }
    } 

    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if ((ds_330.getCellData(i, "pchsClntNo") != "" || ds_330.getCellData(i, "pchsCtrtStDt") != "" || 
             ds_330.getCellData(i, "pchsPchsAmt") != 0 || ds_330.getCellData(i, "pchsVehcl") != "") && 
            (ds_330.getCellData(i, "vehclNo") != "" && ds_330.getCellData(i, "vehclArvDt") != "" && ds_330.getCellData(i, "vehclPchsAmt") != 0)) {
            await $c.win.alert("배차정보를 입력시 위탁계약정보를 입력할수 없습니다.");
            return;
        } 
    }

    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if ((ds_330.getCellData(i, "vehclNo") != "" || ds_330.getCellData(i, "vehclArvDt") != "" || 
             ds_330.getCellData(i, "vehclPchsAmt") != 0) &&
            (ds_330.getCellData(i, "pchsClntNo") != "" && ds_330.getCellData(i, "pchsCtrtStDt") != "" && 
             ds_330.getCellData(i, "pchsPchsAmt") != 0 && ds_330.getCellData(i, "pchsVehcl") != "")) {
            await $c.win.alert("위탁계약정보 입력시 배차정보를 입력할수 없습니다.");
            return;
        } 
    }

    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "confirmYn") == 1) {
            await $c.win.alert("확정된 화물은 저장할수 없습니다");
            return;
        }
    }
    //하차일 날짜 유효성 확인
    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "vehclArvDt") != "") {
            if (!$c.date.isDate(ds_330.getCellData(i, "vehclArvDt"))){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_018,["하차일"]);
                return;
            }
        }
    }

    //위탁계약정보_계약기간 from 날짜 유효성 확인
    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "pchsCtrtStDt") != "") {
            if (!$c.date.isDate(ds_330.getCellData(i, "pchsCtrtStDt"))){
                await $c.gus.cfAlertMsg(MSG_CM_ERR_018,["위탁계약정보_계약기간 from"]);
                return;
            }
        } 
    }
    //계약기간 from 은 실적날짜 이전 확인 
    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "vehclArvDt") > ds_330.getCellData(i, "rsltsStdDt")) {
            await $c.gus.cfAlertMsg("'하차일' 은 '실적날짜'" + ds_330.getCellData(i, "rsltsStdDt") + "이전으로만 입력가능합니다.");
            return; 
        }       
    }
    //계약기간 from 은 실적날짜 이전 확인       
    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "pchsCtrtStDt") > ds_330.getCellData(i, "rsltsStdDt")) {
            await $c.gus.cfAlertMsg("'위탁계약정보_계약기간 from' 은 '실적날짜': " + ds_330.getCellData(i, "rsltsStdDt") + "이전으로만 입력가능합니다.");
            return; 
        }
    }
    //차량번호7~ 9자리 확인            
    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "vehclNo") != ""){       
            var vehclNoLength = ds_330.getCellData(i, "vehclNo");
                if (vehclNoLength.trim().length <7) {
                        await $c.win.alert("배차정보의 차량등록번호는 7자리 이상입니다.");
                        retrun;
                }
                if (vehclNoLength.trim().length >9) {
                    await $c.win.alert("배차정보의 차량등록번호는 9자리 이하입니다.");
                    retrun;
                }
        }
    }

    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        if (ds_330.getCellData(i, "pchsVehcl") != "") {   
            var pchsVehclLength = ds_330.getCellData(i, "pchsVehcl");     
                if (pchsVehclLength.trim().length <7){
                    await $c.win.alert("위탁계약정보의 차량등록번호는 7자리 이상입니다.");
                    retrun;
                }
                if (pchsVehclLength.trim().length >9){
                    await $c.win.alert("위탁계약정보의 차량등록번호는  9자리 이하입니다.");
                    retrun;
                }                 
        }             
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)){ // 저장 하시겠습니까?
        $c.sbm.execute(sbm_save);
    }             
};



//-------------------------------------------------------------------------
// 엑셀 다운로드 
//-------------------------------------------------------------------------
scwin.f_Excel = async function(){
    if (ds_330.getTotalRow() == 0) {
        return;
    }
    var fileName = "화물운송실적신고(업로드)";
    var options = {
        fileName: fileName + ".xlsx", 
        sheetName: fileName,
        type: 1
    }
    await $c.data.downloadGridViewExcel(gr_330, options);
};



//-------------------------------------------------------------------------
// 엑셀 업로드 
//-------------------------------------------------------------------------
scwin.f_upload = async function() {
    var options = {
        // headerExist: 1,
        startRowIndex: 1,
        type: 1,
        status: "C"
    }

    //파일업로드용 hide 그리드 새로 생성
    await udc_grd.uploadGridViewExcel(gr_330_upload, options);  
};

scwin.gr_330_onfilereadend = async function (value) { // =scwin.f_Import
    if (await scwin.f_AddRowUploaded()) {
        // await $c.gus.cfProgressWinClose();
        await $c.gus.cfAlertMsg("업로드작업이 완료되었습니다.");

        ds_330.removeAll();
        ds_330.setJSON(ds_330_upload.getAllJSON());
        ds_330.modifyAllStatus("C");
        totalRows.setValue(ds_330.getTotalRow());
    }
    // gr_330.Redraw = "true"; 
};

//업로드 자료 추가
scwin.f_AddRowUploaded = async function() {   
    // ds_Tmp_FillUse.ImportData(ds_330_FillUse.ExportData(1, ds_330_FillUse.CountRow, true));
    ds_Tmp_FillUse.setJSON(ds_330_FillUse.getAllJSON());

    ds_330_upload.removeAll();  //alertMsg 이후 ds_330에 setJSON 하기 위한 datalist

    for (var i = 0 ; i < ds_Tmp_FillUse.getTotalRow(); i++) {                           
        ds_330_upload.insertRow(i);
        ds_330_upload.setCellData(i, "lobranCd"         , ds_search.get("lobranCd"));
        ds_330_upload.setCellData(i, "odrNo"            , ds_search.get("odrNo"));
        ds_330_upload.setCellData(i, "commSeq"          , ds_search.get("commSeq"));
        ds_330_upload.setCellData(i, "wrkPathSeq"       , ds_search.get("wrkPathSeq"));
        ds_330_upload.setCellData(i, "wrkStpSeq"        , ds_search.get("wrkStpSeq"));
        ds_330_upload.setCellData(i, "transSeq"         , ds_search.get("transSeq"));
        ds_330_upload.setCellData(i, "rsltsStdDt"       , ds_search.get("rsltsStdDt"));
        ds_330_upload.setCellData(i, "ordRegId"         , ds_search.get("ordRegId"));
        ds_330_upload.setCellData(i, "transRegId"       , ds_search.get("transRegId"));  
        ds_330_upload.setCellData(i, "cargoClsCd"       , ds_search.get("cargoClsCd"));            
        ds_330_upload.setCellData(i, "pchsDeptCd"       , ds_search.get("pchsDeptCd"));  

        ds_330_upload.setCellData(i, "bilgClntNo"       , ds_Tmp_FillUse.getCellData(i, "bilgClntNo"));
        ds_330_upload.setCellData(i, "sellAmt"          , ds_Tmp_FillUse.getCellData(i, "sellAmt"));
        ds_330_upload.setCellData(i, "sellVat"          , ds_Tmp_FillUse.getCellData(i, "sellVat"));
        ds_330_upload.setCellData(i, "vehclNo"          , ds_Tmp_FillUse.getCellData(i, "vehclNo"));
        ds_330_upload.setCellData(i, "vehclArvDt"       , ds_Tmp_FillUse.getCellData(i, "vehclArvDt"));
        ds_330_upload.setCellData(i, "vehclPchsAmt"     , ds_Tmp_FillUse.getCellData(i, "vehclPchsAmt"));
        ds_330_upload.setCellData(i, "pchsClntNo"       , ds_Tmp_FillUse.getCellData(i, "pchsClntNo"));
        ds_330_upload.setCellData(i, "pchsCtrtStDt"     , ds_Tmp_FillUse.getCellData(i, "pchsCtrtStDt"));
        ds_330_upload.setCellData(i, "pchsPchsAmt"      , ds_Tmp_FillUse.getCellData(i, "pchsPchsAmt"));
        ds_330_upload.setCellData(i, "pchsVehcl"        , ds_Tmp_FillUse.getCellData(i, "pchsVehcl")); 
        ds_330_upload.setCellData(i, "confirmYn"        , "0");
    }

    return true;
};


//-------------------------------------------------------------------------
// 행 추가
//-------------------------------------------------------------------------
scwin.f_Addrow330 = function() {
    var i = ds_330.getTotalRow();

    ds_330.insertRow(i);
    gr_330.setFocusedCell(i, 0);
    ds_330.setCellData(i, "lobranCd"    ,  ds_search.get("lobranCd"));
    ds_330.setCellData(i, "odrNo"       ,  ds_search.get("odrNo"));
    ds_330.setCellData(i, "commSeq"     ,  ds_search.get("commSeq"));
    ds_330.setCellData(i, "wrkPathSeq"  ,  ds_search.get("wrkPathSeq"));
    ds_330.setCellData(i, "wrkStpSeq"   ,  ds_search.get("wrkStpSeq"));
    ds_330.setCellData(i, "transSeq"    ,  ds_search.get("transSeq"));
    ds_330.setCellData(i, "rsltsStdDt"  ,  ds_search.get("rsltsStdDt"));
    ds_330.setCellData(i, "cargoClsCd"  ,  ds_search.get("cargoClsCd"));
    ds_330.setCellData(i, "pchsDeptCd"  ,  ds_search.get("pchsDeptCd"));
    ds_330.setCellData(i, "ordRegId"    ,  ds_search.get("ordRegId"));
    ds_330.setCellData(i, "transRegId"  ,  ds_search.get("transRegId")); 
    ds_330.setCellData(i, "bilgClntNo"  ,  ds_search.get("bilgClntNo"));
    ds_330.setCellData(i, "sellAmt"     ,  ds_search.get("sellAmt"));
    ds_330.setCellData(i, "sellVat"     ,  ds_search.get("sellVat"));
    ds_330.setCellData(i, "sellTot"     ,  ds_search.get("sellTot"));
    ds_330.setCellData(i, "vehclNo"     ,  ds_search.get("vehclNo"));
    ds_330.setCellData(i, "vehclArvDt"  ,  ds_search.get("vehclArvDt"));
    ds_330.setCellData(i, "vehclPchsAmt",  ds_search.get("vehclPchsAmt"));
    ds_330.setCellData(i, "pchsClntNo"  ,  ds_search.get("pchsClntNo"));
    ds_330.setCellData(i, "pchsCtrtStDt",  ds_search.get("pchsCtrtStDt"));
    ds_330.setCellData(i, "pchsPchsAmt" ,  ds_search.get("pchsPchsAmt"));
    ds_330.setCellData(i, "pchsVehcl"   ,  ds_search.get("pchsVehcl")); 
    ds_330.setCellData(i, "upperCommCd" ,  ds_search.get("upperCommCd")); 
    ds_330.setCellData(i, "upperCommNm" ,  ds_search.get("upperCommNm")); 
    ds_330.setCellData(i, "confirmYn"   ,  "0");
};


//-------------------------------------------------------------------------
// 행 삭제
//-------------------------------------------------------------------------
scwin.f_Del330 = async function() {
    for (var i = 0; i < ds_330.getTotalRow(); i++) {
        //신고일자가 있을시 삭제 불가능
        if (ds_330.getCellData(i,"sndDtm") != "" && ds_330.getCellData(i, "chk") == "1" ){
            await $c.gus.cfAlertMsg((i + 1) + "행에 신고일자가 있어 삭제가 불가능합니다.");
            return; 
        } 

        if (ds_330.getCellData(i,"sndDtm") == "" && ds_330.getCellData(i,"chk") == "1" ){
            // ds_330.DeleteRow(i);
            var rowIdx = ds_330.getRowPosition();
            if (ds_330.getRowStatus(i) == "C") {
                ds_330.removeRow(i);
            } else {
                ds_330.deleteRow(i);
                ds_330.setRowPosition(i);
                ds_330.setCellData(i, "chk", "0");
                gr_330.setCellReadOnly(i, "chk", true);
            }
        }
    }
};


//-------------------------------------------------------------------------
// 행 취소
//-------------------------------------------------------------------------
scwin.f_Cancel330 = function() {
    var rowInx = ds_330.getRowPosition();
    // ds_330.undoRow(ds_330.getRowPosition());
    if(ds_330.getRowStatus(rowInx) == "C"){
        ds_330.removeRow(rowInx);
        gr_330.setFocusedCell(rowInx - 1, 0);
    } else {
        ds_330.undoRow(rowInx);
        gr_330.setCellReadOnly(rowInx, "chk", false);
    }
};




scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    await $c.gus.cfAlertMsg("정상적으로 반영되었습니다.");
    scwin.f_Retrieve();
    $c.win.closePopup();
};


scwin.sbm_retrieve_submitdone = function (e) {
    var rowCnt = ds_330.getTotalRow();
    totalRows.setValue(rowCnt);
    if(rowCnt == 0){
        $c.gus.cfAlertMsg("조회결과가 존재하지 않습니다."); 
    }
};


scwin.gr_330_onafteredit = function (rowIndex, columnIndex, value) {
    //계약금액, 부가세, 운송료, 위탁계약금액 value == ""이면 "0" 세팅
    var colid = gr_330.getFocusedColumnID();

    if (value != "") {
        return;
    }

    switch (colid) {
        case "sellAmt":
            ds_330.setCellData(rowIndex, "sellAmt", "0");
            break;
        case "sellVat":
            ds_330.setCellData(rowIndex, "sellVat", "0");
            break;
        case "vehclPchsAmt":
            ds_330.setCellData(rowIndex, "vehclPchsAmt", "0");
            break;
        case "pchsPchsAmt":
            ds_330.setCellData(rowIndex, "pchsPchsAmt", "0");
            break;
    }
};
